163→/// Format: changeID commitID first-line (single line).
164→pub fn format_commit_short(commit: &Commit) -> String {
165→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
166→    let change_short = &change_hex[..change_hex.len().min(12)];
167→    let commit_hex = commit.id().hex();
168→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
169→    let first_line = commit.description().lines().next().unwrap_or("");
170→    if first_line.is_empty() {
171→        format!("{change_short} {commit_short} (no description set)")
172→    } else {
173→        format!("{change_short} {commit_short} {first_line}")
174→    }
175→}
176→
177→/// Format: changeID commitID first-line, then remaining description lines.
178→pub fn format_commit_full(commit: &Commit) -> String {
179→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
180→    let change_short = &change_hex[..change_hex.len().min(12)];
181→    let commit_hex = commit.id().hex();
182→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
183→    let desc = commit.description();
184→    if desc.is_empty() {
185→        format!("{change_short} {commit_short} (no description set)")
186→    } else {
187→        let mut lines = desc.lines();
188→        let first_line = lines.next().unwrap_or("");
189→        let mut result = format!("{change_short} {commit_short} {first_line}");
190→        for line in lines {
191→            result.push('\n');
192→            result.push_str(line);
193→        }
194→        result
195→    }
196→}
