109→fn show_one_commit(
110→    commit: &Commit,
111→    workspace: &Workspace,
112→    repo: &Arc<ReadonlyRepo>,
113→    file_limit: FileLimit,
114→    is_primary: bool,
115→) -> Result<(), Box<dyn std::error::Error>> {
116→    // Author
117→    let author = commit.author();
118→    println!(
119→        "Author:    {} <{}> ({})",
120→        author.name,
121→        author.email,
122→        format_timestamp(&author.timestamp)
123→    );
124→
125→    // Committer
126→    let committer = commit.committer();
127→    println!(
128→        "Committer: {} <{}> ({})",
129→        committer.name,
130→        committer.email,
131→        format_timestamp(&committer.timestamp)
132→    );
133→
134→    // Ids
135→    let ids_line = common::format_commit_short(commit);
136→    if is_primary {
137→        println!("Ids:       {}", common::bold(&ids_line));
138→    } else {
139→        println!("Ids:       {ids_line}");
140→    }
141→
142→    // Parents
143→    let root_commit_id = repo.store().root_commit_id().clone();
144→    for parent_id in commit.parent_ids() {
145→        if *parent_id == root_commit_id {
146→            continue;
147→        }
148→        let parent = repo.store().get_commit(parent_id)?;
149→        println!("Parent:    {}", common::format_commit_short(&parent));
150→    }
151→
152→    // Children
153→    let children_ids =
154→        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
155→    for child_id in &children_ids {
156→        if *child_id == root_commit_id {
157→            continue;
158→        }
159→        let child = repo.store().get_commit(child_id)?;
160→        println!("Child:     {}", common::format_commit_short(&child));
161→    }
162→
163→    // Branches
164→    let branches_str = format_branches(commit, workspace, repo)?;
165→    println!("Branches:  {branches_str}");
166→
167→    // Follows
168→    let follows = find_nearest_tag(commit, workspace, repo, true)?;
169→    println!("Follows:   {}", follows.as_deref().unwrap_or(""));
170→
171→    // Precedes
172→    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
173→    println!("Precedes:  {}", precedes.as_deref().unwrap_or(""));
174→
175→    // Description (body only — title is on the Ids line)
176→    print_description(commit);
177→
178→    // Changed files
179→    if file_limit != FileLimit::None {
180→        print_diff(commit, repo, file_limit)?;
181→    }
182→
183→    Ok(())
184→}
185→
186→fn find_nearest_tag(
187→    commit: &Commit,
188→    workspace: &Workspace,
189→    repo: &Arc<ReadonlyRepo>,
190→    ancestor: bool,
191→) -> Result<Option<String>, Box<dyn std::error::Error>> {
192→    let commit_hex = commit.id().hex();
193→
194→    let revset_str = if ancestor {
195→        format!("heads(tags() & ::{})", commit_hex)
196→    } else {
197→        format!("roots(tags() & {}::)", commit_hex)
198→    };
199→
200→    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
201→    if tag_ids.is_empty() {
202→        return Ok(None);
203→    }
204→
205→    let tag_id = &tag_ids[0];
206→    let view = repo.view();
207→    for (name, local_remote) in view.tags() {
208→        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
209→            return Ok(Some(name.as_str().to_string()));
210→        }
211→    }
212→
213→    Ok(None)
214→}
215→
216→fn format_branches(
217→    commit: &Commit,
218→    workspace: &Workspace,
219→    repo: &Arc<ReadonlyRepo>,
220→) -> Result<String, Box<dyn std::error::Error>> {
221→    let commit_hex = commit.id().hex();
222→    let view = repo.view();
223→    let mut names: Vec<String> = Vec::new();
224→
225→    for (name, local_remote) in view.bookmarks() {
226→        for bookmark_id in local_remote.local_target.added_ids() {
227→            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
228→            let results = common::resolve_revset(workspace, repo, &revset_str)?;
229→            if !results.is_empty() {
230→                names.push(name.as_str().to_string());
231→                break;
232→            }
233→        }
234→
235→        for (remote_name, remote_ref) in &local_remote.remote_refs {
236→            if remote_name.as_str() == "git" {
237→                continue;
238→            }
239→            for bookmark_id in remote_ref.target.added_ids() {
240→                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
241→                let results = common::resolve_revset(workspace, repo, &revset_str)?;
242→                if !results.is_empty() {
243→                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
244→                    break;
245→                }
246→            }
247→        }
248→    }
249→
250→    Ok(names.join(", "))
251→}
252→
253→fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
254→    let millis = ts.timestamp.0;
255→    let secs = millis / 1000;
256→    let tz_minutes = ts.tz_offset;
257→
258→    let dt = chrono::DateTime::from_timestamp(secs, 0)
259→        .unwrap_or_default()
260→        .with_timezone(
261→            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()),
262→        );
263→
264→    dt.format("%Y-%m-%d %H:%M:%S").to_string()
265→}
266→
267→fn print_description(commit: &Commit) {
268→    let desc = commit.description();
269→    let body: String = desc
270→        .lines()
271→        .skip(1)
272→        .skip_while(|l| l.is_empty())
273→        .collect::<Vec<_>>()
274→        .join("\n");
275→
276→    println!("Description:");
277→    for line in body.lines() {
278→        println!("    {line}");
279→    }
280→}
281→
282→fn print_diff(
283→    commit: &Commit,
284→    repo: &Arc<ReadonlyRepo>,
285→    file_limit: FileLimit,
286→) -> Result<(), Box<dyn std::error::Error>> {
287→    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
288→    let commit_tree = commit.tree();
289→
290→    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
291→
292→    let mut lines: Vec<String> = Vec::new();
293→    for entry in diff_iter {
294→        let diff = entry.values?;
295→        let before = diff.before.as_resolved().cloned().flatten();
296→        let after = diff.after.as_resolved().cloned().flatten();
297→
298→        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
299→        {
300→            continue;
301→        }
302→
303→        let path_str = entry.path.as_internal_file_string().to_string();
304→
305→        let line = match (before, after) {
306→            (None, Some(value)) => {
307→                format!("    Added {} {path_str}", file_type_str(&value))
308→            }
309→            (Some(_), None) => {
310→                format!(
311→                    "    Removed {} {path_str}",
312→                    file_type_str_from_merged(&diff.before),
313→                )
314→            }
315→            (Some(_), Some(value)) => {
316→                format!("    Modified {} {path_str}", file_type_str(&value))
317→            }
318→            (None, None) => continue,
319→        };
320→        lines.push(line);
321→    }
322→
323→    let total = lines.len();
324→    let cap = match file_limit {
325→        FileLimit::All | FileLimit::None => 0,
326→        FileLimit::Cap(n) => n,
327→    };
328→    let show_all = cap == 0 || total <= cap;
329→
330→    if show_all {
331→        println!("Changed files: {total}");
332→        for line in &lines {
333→            println!("{line}");
334→        }
335→    } else {
336→        println!("Changed files: {total}, showing first {cap}");
337→        for line in &lines[..cap] {
338→            println!("{line}");
339→        }
340→    }
341→
342→    Ok(())
343→}
344→
345→fn file_type_str(value: &TreeValue) -> &'static str {
346→    match value {
347→        TreeValue::File {
348→            executable: false, ..
349→        } => "regular file",
350→        TreeValue::File {
351→            executable: true, ..
352→        } => "executable file",
353→        TreeValue::Symlink(_) => "symlink",
354→        TreeValue::Tree(_) => "tree",
355→        TreeValue::GitSubmodule(_) => "git submodule",
356→    }
357→}
358→
359→fn file_type_str_from_merged(merged: &jj_lib::merge::Merge<Option<TreeValue>>) -> &'static str {
360→    if let Some(Some(value)) = merged.as_resolved() {
361→        file_type_str(value)
362→    } else {
363→        "file"
364→    }
365→}
