    let cli = parse(&["vc-x1", "chid", "-R", ".", "-R", ".claude"]);
    if let Commands::Chid(args) = cli.command {
        assert_eq!(args.repos, vec![PathBuf::from("."), PathBuf::from(".claude")]);
    } else { panic!("expected Chid"); }
}
```

Add similar tests for desc, list, show.

